command:
// =========================
// DUNGEON OVERVIEW GENERATOR
// Sandbox Generator
// =========================

function roll(sides) {
    return Math.ceil(Math.random() * sides);
}

// -------------------------
// DUNGEON TYPES
// -------------------------

const dungeonTypes = [
    "Ancient Tomb",
"Abandoned Mine",
"Natural Cave",
"Bandit Hideout",
"Goblin Warrens",
"Lost Temple",
"Wizard Laboratory",
"Forgotten Fortress",
"Underground City",
"Crypt",
"Sewers",
"Ancient Ruins"
];

const dungeonThemes = [
    "Decay",
"Death",
"Fire",
"Ice",
"Nature",
"Corruption",
"Madness",
"Undead",
"Demons",
"Lost Civilization",
"Forbidden Knowledge",
"Monsters"
];

const dungeonPurposes = [
    "Burial site",
"Military outpost",
"Religious center",
"Prison",
"Research facility",
"Treasure vault",
"Refuge",
"Monster lair",
"Ancient city",
"Trade route",
"Secret meeting place",
"Portal nexus"
];

// -------------------------
// CROSS SECTION
// -------------------------

const crossSections = [
    "Single Level",
"Single Level",
"Single Level",
"Single Level",
"Two Levels",
"Two Levels",
"Three Levels",
"Three Levels",
"Four Levels",
"Five Levels",
"Six Levels",
"Mega Dungeon"
];

// -------------------------
// ROOM DENSITY
// -------------------------

const roomDensity = [
    { name: "Small", roomsPerLevel: "1d6+4" },
{ name: "Medium", roomsPerLevel: "2d6+6" },
{ name: "Large", roomsPerLevel: "3d6+9" }
];

// -------------------------
// ROLLS
// -------------------------

let typeRoll = roll(12);
let dungeonType = dungeonTypes[typeRoll - 1];

let themeRoll = roll(12);
let dungeonTheme = dungeonThemes[themeRoll - 1];

let purposeRoll = roll(12);
let dungeonPurpose = dungeonPurposes[purposeRoll - 1];

let crossSectionRoll = roll(12);
let crossSection = crossSections[crossSectionRoll - 1];

// -------------------------
// LEVELS
// -------------------------

let levels = 1;

switch(crossSection) {
    case "Single Level":
        levels = 1;
        break;
    case "Two Levels":
        levels = 2;
        break;
    case "Three Levels":
        levels = 3;
        break;
    case "Four Levels":
        levels = 4;
        break;
    case "Five Levels":
        levels = 5;
        break;
    case "Six Levels":
        levels = 6;
        break;
    case "Mega Dungeon":
        levels = roll(6) + 6;
        break;
}

// -------------------------
// SIZE
// -------------------------

let sizeRoll = roll(3);
let sizeData = roomDensity[sizeRoll - 1];

let totalRooms = 0;
let levelData = [];

for (let i = 1; i <= levels; i++) {

    let rooms;

    if (sizeData.name === "Small") {
        let r = roll(6);
        rooms = r + 4;

        levelData.push({
            level: i,
            formula: `1d6+4`,
                roll: r,
                rooms
        });

    } else if (sizeData.name === "Medium") {

        let r1 = roll(6);
        let r2 = roll(6);

        rooms = r1 + r2 + 6;

        levelData.push({
            level: i,
            formula: `2d6+6`,
                roll: `${r1}+${r2}`,
                rooms
        });

    } else {

        let r1 = roll(6);
        let r2 = roll(6);
        let r3 = roll(6);

        rooms = r1 + r2 + r3 + 9;

        levelData.push({
            level: i,
            formula: `3d6+9`,
                roll: `${r1}+${r2}+${r3}`,
                rooms
        });

    }

    totalRooms += rooms;
}

// -------------------------
// SPECIAL ROOMS
// -------------------------

let specialRoomRoll = roll(6);
let specialRooms = specialRoomRoll + Math.floor(levels / 2);

// -------------------------
// DANGER
// -------------------------

let dangerRoll = roll(6);

let danger;

switch(dangerRoll) {
    case 1:
        danger = "Mostly abandoned";
        break;
    case 2:
        danger = "Minor threats";
        break;
    case 3:
        danger = "Moderate danger";
        break;
    case 4:
        danger = "Hostile dungeon";
        break;
    case 5:
        danger = "Extremely dangerous";
        break;
    case 6:
        danger = "Deadly";
        break;
}

// -------------------------
// OUTPUT
// -------------------------

let output = `
<h2>Dungeon Overview Generator</h2>

<h3>Identity</h3>

<p><b>Dungeon Type Roll:</b> d12 = ${typeRoll}</p>
<p><b>Dungeon Type:</b> ${dungeonType}</p>

<p><b>Theme Roll:</b> d12 = ${themeRoll}</p>
<p><b>Theme:</b> ${dungeonTheme}</p>

<p><b>Purpose Roll:</b> d12 = ${purposeRoll}</p>
<p><b>Purpose:</b> ${dungeonPurpose}</p>

<hr>

<h3>Structure</h3>

<p><b>Cross Section Roll:</b> d12 = ${crossSectionRoll}</p>
<p><b>Cross Section:</b> ${crossSection}</p>

<p><b>Levels:</b> ${levels}</p>

<p><b>Size Roll:</b> d3 = ${sizeRoll}</p>
<p><b>Dungeon Size:</b> ${sizeData.name}</p>

<hr>

<h3>Level Breakdown</h3>

<ul>
${levelData.map(l => `
    <li>
    Level ${l.level}<br>
    Formula: ${l.formula}<br>
    Roll: ${l.roll}<br>
    Rooms: ${l.rooms}
    </li>
    `).join("")}
    </ul>

    <p><b>Total Rooms:</b> ${totalRooms}</p>

    <hr>

    <h3>Special Rooms</h3>

    <p><b>Special Room Roll:</b> d6 = ${specialRoomRoll}</p>
    <p><b>Special Rooms:</b> ${specialRooms}</p>

    <hr>

    <h3>Danger</h3>

    <p><b>Danger Roll:</b> d6 = ${dangerRoll}</p>
    <p><b>Danger:</b> ${danger}</p>

    <hr>

    <h3>Quick Summary</h3>

    <p>
    This dungeon is a <b>${dungeonType.toLowerCase()}</b>
    built as a <b>${dungeonPurpose.toLowerCase()}</b>.
    Its theme revolves around <b>${dungeonTheme.toLowerCase()}</b>.

    The dungeon has <b>${levels}</b> level${levels === 1 ? "" : "s"},
contains roughly <b>${totalRooms}</b> rooms,
and includes approximately <b>${specialRooms}</b> special rooms.

Overall threat level: <b>${danger}</b>.
</p>
`;

ChatMessage.create({
    speaker: ChatMessage.getSpeaker(),
                   content: output
});
